# Getting Started with Next.js

Next.js makes React development simpler with file-based routing,
server components, and built-in optimization.

<Callout type="info">
  This tutorial uses Next.js 14+ with the App Router.
</Callout>

## Creating Your First Page

In Next.js, every file inside `app/` becomes a route automatically:

```tsx
// app/about/page.tsx
export default function AboutPage() {
  return <h1>About Me</h1>;
}
```

Visit `/about` and you will see your page.

## Table of Contents

This heading structure automatically generates a table of contents
on the right sidebar of the blog post.

## Fetching Data

Server components can fetch data directly without useEffect:

```tsx
async function getData() {
  const res = await fetch('https://api.example.com/posts');
  return res.json();
}

export default async function Blog() {
  const posts = await getData();
  return (
    <ul>
      {posts.map((post) => (
        <li key={post.id}>{post.title}</li>
      ))}
    </ul>
  );
}
```

import fs from 'fs';
import path from 'path';
import matter from 'gray-matter';
import readingTime from 'reading-time';

const BLOG_DIR = path.join(process.cwd(), 'content', 'blog');

export interface PostMeta {
  slug: string;
  title: string;
  date: string;
  excerpt: string;
  tags: string[];
  category: string;
  image: string;
  readingTime: string;
  featured: boolean;
}

export interface TableOfContentsItem {
  id: string;
  title: string;
  level: number;
}

export function getAllPostSlugs(): string[] {
  return fs
    .readdirSync(BLOG_DIR)
    .filter((f) => f.endsWith('.mdx'))
    .map((f) => f.replace(/\.mdx$/, ''));
}

export function getPostBySlug(slug: string) {
  const filePath = path.join(BLOG_DIR, `${slug}.mdx`);
  const source = fs.readFileSync(filePath, 'utf8');
  const { data, content } = matter(source);
  const stats = readingTime(content);

  // Extract headings for table of contents
  const headings: TableOfContentsItem[] = [];
  const headingRegex = /^(#{2,4})\s+(.+)$/gm;
  let match;
  while ((match = headingRegex.exec(content)) !== null) {
    const level = match[1].length;
    const title = match[2].trim();
    const id = title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
    headings.push({ id, title, level });
  }

  return {
    meta: {
      slug,
      title: data.title,
      date: data.date,
      excerpt: data.excerpt || '',
      tags: data.tags || [],
      category: data.category || 'Uncategorized',
      image: data.image || '',
      readingTime: stats.text,
      featured: data.featured || false,
    } as PostMeta,
    content,
    headings,
  };
}

export function getAllPosts(): PostMeta[] {
  const slugs = getAllPostSlugs();
  return slugs
    .map((slug) => getPostBySlug(slug).meta)
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
}

export function getPostsByTag(tag: string): PostMeta[] {
  return getAllPosts().filter((p) => p.tags.includes(tag));
}

export function getPostsByCategory(category: string): PostMeta[] {
  return getAllPosts().filter((p) => p.category === category);
}

export function getAllTags(): { name: string; count: number }[] {
  const tagCounts = new Map<string, number>();
  getAllPosts().forEach((post) => {
    post.tags.forEach((tag) => {
      tagCounts.set(tag, (tagCounts.get(tag) || 0) + 1);
    });
  });
  return Array.from(tagCounts.entries())
    .map(([name, count]) => ({ name, count }))
    .sort((a, b) => b.count - a.count);
}

export function getAllCategories(): string[] {
  const categories = new Set(getAllPosts().map((p) => p.category));
  return Array.from(categories).sort();
}

