'use client';

import { useEffect, useState } from 'react';
import type { TableOfContentsItem } from '@/lib/blog';

interface Props {
  headings: TableOfContentsItem[];
}

export default function TableOfContents({ headings }: Props) {
  const [activeId, setActiveId] = useState<string>('');

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setActiveId(entry.target.id);
          }
        });
      },
      { rootMargin: '-80px 0px -80% 0px' }
    );

    headings.forEach(({ id }) => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });

    return () => observer.disconnect();
  }, [headings]);

  return (
    <nav aria-label="Table of Contents">
      <h3 className="text-sm font-bold uppercase tracking-wider text-gray-400 mb-4">
        On This Page
      </h3>
      <ul className="space-y-2">
        {headings.map(({ id, title, level }) => (
          <li key={id} style={{ paddingLeft: `${(level - 2) * 16}px` }}>
            <a
              href={`#${id}`}
              className={`block text-sm transition-colors ${
                activeId === id
                  ? 'text-blue-500 font-medium'
                  : 'text-gray-400 hover:text-gray-600 dark:hover:text-gray-300'
              }`}
            >
              {title}
            </a>
          </li>
        ))}
      </ul>
    </nav>
  );
}

import { ReactNode } from 'react';

function Callout({ type = 'info', children }: { type?: 'info' | 'warning' | 'tip'; children: ReactNode }) {
  const styles = {
    info:    'bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-800 text-blue-800 dark:text-blue-200',
    warning: 'bg-amber-50 dark:bg-amber-900/20 border-amber-200 dark:border-amber-800 text-amber-800 dark:text-amber-200',
    tip:     'bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800 text-green-800 dark:text-green-200',
  };
  const icons = { info: '\u2139\uFE0F', warning: '\u26A0\uFE0F', tip: '\uD83D\uDCA1' };

  return (
    <aside className={`my-6 p-4 rounded-lg border-l-4 ${styles[type]}`}>
      <span className="mr-2">{icons[type]}</span>
      <div className="inline">{children}</div>
    </aside>
  );
}

function CodeTabs({ children, labels }: { children: ReactNode[]; labels: string[] }) {
  return (
    <div className="my-4 rounded-lg border border-gray-200 dark:border-gray-700 overflow-hidden">
      <div className="flex bg-gray-100 dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700">
        {labels.map((label) => (
          <span key={label} className="px-4 py-2 text-sm font-medium">{label}</span>
        ))}
      </div>
      <div>{children}</div>
    </div>
  );
}

