'use client';

import { useEffect, useState } from 'react';

interface Props {
  slug: string;
  trackView?: boolean;
}

export default function ViewCounter({ slug, trackView = false }: Props) {
  const [views, setViews] = useState<number | null>(null);

  useEffect(() => {
    // Fetch current views
    fetch(`/api/views/${slug}`)
      .then((res) => res.json())
      .then((data) => setViews(data.views))
      .catch(() => setViews(null));

    // Increment view count (only on post page, not listing)
    if (trackView) {
      fetch(`/api/views/${slug}`, { method: 'POST' }).catch(() => {});
    }
  }, [slug, trackView]);

  if (views === null) return null;

  return (
    <span className="text-sm text-gray-400">
      {views.toLocaleString()} views
    </span>
  );
}

'use client';
import { useState, FormEvent } from 'react';

export default function ContactForm() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [message, setMessage] = useState('');
  const [status, setStatus] = useState<'idle' | 'sending' | 'sent' | 'error'>('idle');
  const [errors, setErrors] = useState<Record<string, string>>({});

  function validate() {
    const errs: Record<string, string> = {};
    if (name.trim().length < 2) errs.name = 'Name is required';
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) errs.email = 'Valid email required';
    if (message.trim().length < 10) errs.message = 'Message must be at least 10 characters';
    setErrors(errs);
    return Object.keys(errs).length === 0;
  }

  async function handleSubmit(e: FormEvent) {
    e.preventDefault();
    if (!validate()) return;
    setStatus('sending');
    try {
      const res = await fetch('https://formspree.io/f/YOUR_FORM_ID', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Accept: 'application/json' },
        body: JSON.stringify({ name, email, message }),
      });
      if (res.ok) {
        setStatus('sent');
        setName(''); setEmail(''); setMessage('');
      } else {
        setStatus('error');
      }
    } catch {
      setStatus('error');
    }
  }

  if (status === 'sent') {
    return (
      <div className="text-center py-12">
        <p className="text-xl font-bold text-green-500">Message sent!</p>
        <p className="text-gray-500 mt-2">I will get back to you within 48 hours.</p>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="max-w-lg mx-auto space-y-4" noValidate>
      <div>
        <label htmlFor="name" className="block text-sm font-semibold mb-1">Name</label>
        <input id="name" value={name} onChange={(e) => setName(e.target.value)}
               className="w-full px-4 py-2.5 rounded-lg border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-800" />
        {errors.name && <span className="text-sm text-red-500">{errors.name}</span>}
      </div>
      <div>
        <label htmlFor="email" className="block text-sm font-semibold mb-1">Email</label>
        <input id="email" type="email" value={email} onChange={(e) => setEmail(e.target.value)}
               className="w-full px-4 py-2.5 rounded-lg border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-800" />
        {errors.email && <span className="text-sm text-red-500">{errors.email}</span>}
      </div>
      <div>
        <label htmlFor="message" className="block text-sm font-semibold mb-1">Message</label>
        <textarea id="message" rows={5} value={message} onChange={(e) => setMessage(e.target.value)}
                  className="w-full px-4 py-2.5 rounded-lg border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-800" />
        {errors.message && <span className="text-sm text-red-500">{errors.message}</span>}
      </div>
      <button type="submit" disabled={status === 'sending'}
              className="w-full py-3 bg-blue-500 text-white rounded-lg font-semibold hover:bg-blue-600 transition disabled:opacity-50">
        {status === 'sending' ? 'Sending...' : 'Send Message'}
      </button>
      {status === 'error' && <p className="text-sm text-red-500 text-center">Something went wrong. Please try again.</p>}
    </form>
  );
}

